import 'package:equatable/equatable.dart';

/// Result of a server-side CSV export — a signed download URL plus metadata.
class ExportResult extends Equatable {
  const ExportResult({
    required this.url,
    required this.expiresAt,
    required this.rowCount,
  });

  /// Signed download URL (24h TTL, generated by the `export-csv` function).
  final String url;

  /// When the signed URL stops working.
  final DateTime expiresAt;

  /// Number of expense rows included in the export.
  final int rowCount;

  @override
  List<Object?> get props => <Object?>[url, expiresAt, rowCount];
}
